import React, { useState } from 'react';
import {Button} from './Button';
import { Link } from 'react-router-dom';
import './Footer.css';


function Footer() {
  const [status, setStatus] = useState("Submit");
  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus("Sending...");
    const { name, email, message } = e.target.elements;
    let details = {
      name: name.value,
      email: email.value,
      message: message.value,
    };
    let response = await fetch("http://localhost:5000/contact", {
      method: "POST",
      headers: {
        "Content-Type": "application/json;charset=utf-8",
      },
      body: JSON.stringify(details),
    });
    setStatus("Submit");
    let result = await response.json();
    alert(result.status);
  };
  return (
    <div className='footer-container'>
      <section className="footer-tab">
        <p className="footer-heading">
             Me contacter
        </p>
        <div className="input">
          <form onSubmit={handleSubmit}>
            <div>
              <label htmlFor="name">Name:</label>
              <input type="text" id="name" required />
            </div>
            <div>
              <label htmlFor="email">Email:</label>
              <input type="email" id="email" required />
            </div>
            <div>
              <label htmlFor="message">Message:</label>
              <textarea id="message" required />
            </div>
            <button type="submit">{status}</button>
          </form>

          {/* <form>
            <label>
              Nom
              <input type="text" name="name" placeholder="First Name" className="footer-input"/>
            </label>
            <label>
              Prénom
              <input type="text" name="name" placeholder="Last Name" className="footer-input" />
            </label><br>
            </br> <label>
              Email
            <input types="email" name="email" placeholder="Your Email" className="footer-input" />
            </label>
           <Button buttonStyle='btn-outline'> Post </Button>
          </form> */}
        </div>
      </section>
      <div className="footer-links">
        <div className="footer-link-wrapper">
          <div className="footer-link-items">
            <h2> About me </h2>
            <Link to='/home'> How it works </Link>
          </div>
          <div className="footer-link-items">
            <h2> Follow me </h2>
            <Link to='/'> Instagram </Link>
          </div>
        </div>
      </div>
      <section className="social-media">
        <div className="social-media-wrap">
          <Link to="/" className="social-logo">
            <i className="fab fa-typo3"></i>
          </Link>
        </div>
        <div className="social-icons">
          <Link className="social-icon-link instagram" to="/" aria-label='Instagram'>
           <i className="fab fa-instagram" />
          </Link>
        </div>
      </section>
    </div>
  )
}
export default Footer;
